 import { useState } from "react";
import { Navigate, useNavigate } from "react-router-dom";

function Dashboard() {
  const navigate = useNavigate();

  const isLoggedIn = localStorage.getItem("isLoggedIn");

  if (!isLoggedIn) {
    return <Navigate to="/login" />;
  }

  const [posts, setPosts] = useState([
    {
      id: 1,
      title: "MERN Stack Guide",
      date: "June 2026",
      status: "Published",
    },
    {
      id: 2,
      title: "React Tutorial",
      date: "June 2026",
      status: "Draft",
    },
  ]);

  const handleDelete = (id) => {
    const updatedPosts = posts.filter(
      (post) => post.id !== id
    );

    setPosts(updatedPosts);

    alert("Post Deleted Successfully!");
  };

  const handleEdit = (id) => {
    alert(`Editing Post ID: ${id}`);

    // Later:
    // navigate(`/edit/${id}`);
  };

  return (
    <div
      style={{
        width: "90%",
        margin: "40px auto",
      }}
    >
      <h1>My Posts</h1>
      <div className="stats">

<div className="stat-card">
📄 12 Posts
</div>
 <div className="stats-container">
  <div className="stat-card">
    <span>📄</span>
    <h3>Total Posts</h3>
    <p>12</p>
  </div>

  <div className="stat-card">
    <span>❤️</span>
    <h3>Total Likes</h3>
    <p>350</p>
  </div>

  <div className="stat-card">
    <span>💬</span>
    <h3>Comments</h3>
    <p>89</p>
  </div>

  <div className="stat-card">
    <span>👥</span>
    <h3>Followers</h3>
    <p>1024</p>
  </div>
</div>
</div>

      <table
        style={{
          width: "100%",
          borderCollapse: "collapse",
        }}
      >
        <thead>
          <tr>
            <th>Title</th>
            <th>Date</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>

        <tbody>
          {posts.map((post) => (
            <tr key={post.id}>
              <td>{post.title}</td>
              <td>{post.date}</td>
              <td>{post.status}</td>

              <td>
                <button
                  onClick={() => handleEdit(post.id)}
                  style={{
                    marginRight: "10px",
                    cursor: "pointer",
                  }}
                >
                  ✏️ Edit
                </button>

                <button
                  onClick={() => handleDelete(post.id)}
                  style={{
                    cursor: "pointer",
                  }}
                >
                  🗑️ Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Dashboard;
